// src/utils/theme.js

export const colors = {
  // Fondos
  bg:         '#0A0E1A',
  bgCard:     '#111827',
  bgElevated: '#1A2235',

  // Acento principal — azul índigo profundo
  accent:     '#4F7EF7',
  accentSoft: '#1E3A6E',
  accentGlow: 'rgba(79, 126, 247, 0.18)',

  // Verdes para éxito / completado
  success:     '#2DD4A0',
  successSoft: '#0D3D2D',

  // Ámbar para advertencias
  warn:     '#F59E0B',
  warnSoft: '#3B2506',

  // Rojo para alertas
  danger:     '#F87171',
  dangerSoft: '#3D1010',

  // Texto
  textPrimary:   '#F0F4FF',
  textSecondary: '#8896B3',
  textMuted:     '#4A5568',

  // Bordes
  border:      '#1E293B',
  borderLight: '#2D3F5C',
};

export const fonts = {
  heading: 'System',   // Se puede reemplazar por una custom con expo-font
  body:    'System',
};

export const radius = {
  sm: 8,
  md: 12,
  lg: 16,
  xl: 24,
  full: 999,
};

export const spacing = {
  xs: 4,
  sm: 8,
  md: 16,
  lg: 24,
  xl: 32,
};
